"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import Image from "next/image";
import { useRouter } from "next/navigation";

import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

import { XCircle, AlertTriangle, Mail } from "lucide-react";

import api from "@/lib/axios";
import { getOwnerProfile } from "@/lib/owner";

export default function OwnerRejectedPage() {
  const router = useRouter();

  const [loading, setLoading] = useState(true);
  const [businessName, setBusinessName] = useState<string>("");
  const [rejectReason, setRejectReason] = useState<string>("");

  useEffect(() => {
    const load = async () => {
      try {
        // 1. Kiểm tra user
        const meRes = await api.get("/auth/me");
        const user = meRes.data.user;

        if (!user || user.role !== "OWNER") {
          router.push("/login");
          return;
        }

        // 2. Lấy hồ sơ
        const profile = await getOwnerProfile();

        // Nếu không phải rejected → điều hướng về đúng trang
        if (profile.status === "pending") {
          router.push("/owner/pending");
          return;
        }
        if (profile.status === "approved") {
          router.push("/owner/dashboard");
          return;
        }

        setBusinessName(profile.business_name || "Doanh nghiệp của bạn");
        setRejectReason(
          profile.reject_reason ||
            "Hồ sơ của bạn không được phê duyệt. Vui lòng kiểm tra lại giấy tờ."
        );
      } catch (err) {
        console.error(err);
        router.push("/login");
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [router]);

  if (loading) {
    return (
      <main className="min-h-screen flex items-center justify-center">
        <p className="text-muted-foreground animate-pulse">
          Đang tải thông tin...
        </p>
      </main>
    );
  }

  return (
    <main className="min-h-screen bg-gradient-to-br from-red-50 to-orange-50 flex items-center justify-center p-4">
      <Card className="max-w-2xl w-full p-8 md:p-12 shadow-lg">
        {/* Logo */}
        <div className="flex justify-center mb-6">
          <Image
            src="/hcmut-logo.png"
            alt="HCMUT Logo"
            width={80}
            height={80}
            className="object-contain"
          />
        </div>

        {/* Status Icon */}
        <div className="flex justify-center mb-6">
          <div className="w-24 h-24 bg-red-100 rounded-full flex items-center justify-center">
            <XCircle className="w-12 h-12 text-red-600" />
          </div>
        </div>

        {/* Title */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold mb-3">
            Hồ Sơ Chủ Sân Của Bạn Đã Bị Từ Chối
          </h1>
          <p className="text-muted-foreground text-lg">
            Rất tiếc, hồ sơ của <strong>{businessName}</strong> chưa được phê
            duyệt.
          </p>
        </div>

        {/* Rejection Info */}
        <Card className="bg-muted/50 p-6 mb-6 border">
          <div className="flex items-start gap-3 mb-4">
            <AlertTriangle className="w-5 h-5 text-amber-600 mt-0.5" />
            <div className="flex-1">
              <h3 className="font-semibold mb-2">Lý Do Từ Chối</h3>
              <p className="text-sm text-muted-foreground">{rejectReason}</p>
            </div>
          </div>

          <div className="pt-4 border-t">
            <h3 className="font-semibold mb-1">Ghi chú từ hệ thống</h3>
            <p className="text-sm text-muted-foreground">
              Vui lòng chuẩn bị lại giấy tờ và đăng ký lại khi thông tin đã đầy
              đủ và chính xác.
            </p>
          </div>
        </Card>

        {/* What next */}
        <Card className="bg-blue-50 border-blue-200 p-6 mb-8">
          <h3 className="font-semibold mb-3">Bạn có thể làm gì tiếp theo?</h3>
          <ol className="space-y-2 text-sm text-muted-foreground">
            <li>1. Kiểm tra lại toàn bộ thông tin và giấy tờ đã gửi.</li>
            <li>2. Cập nhật lại các giấy tờ còn thiếu hoặc sai.</li>
            <li>3. Đăng ký lại tài khoản chủ sân với hồ sơ đã chỉnh sửa.</li>
          </ol>
        </Card>

        {/* Contact */}
        <Card className="bg-muted/50 p-4 mb-8">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-primary rounded-full flex items-center justify-center flex-shrink-0">
              <Mail className="w-5 h-5 text-primary-foreground" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-medium">Cần hỗ trợ thêm?</p>
              <p className="text-xs text-muted-foreground">
                Liên hệ với chúng tôi để được hỗ trợ về quy trình duyệt hồ sơ.
              </p>
            </div>
          </div>
        </Card>

        {/* Actions */}
        <div className="flex flex-col sm:flex-row gap-3">
          <Button asChild className="flex-1">
            <Link href="/register">Đăng Ký Lại</Link>
          </Button>
          <Button asChild variant="outline" className="flex-1 bg-transparent">
            <Link href="/contact">Liên Hệ Hỗ Trợ</Link>
          </Button>
        </div>

        <div className="mt-6 text-center">
          <Link href="/" className="text-sm text-primary hover:underline">
            Về Trang Chủ
          </Link>
        </div>
      </Card>
    </main>
  );
}
